#include "test_harness.h"
#include <cstdio>

// Helper: Create a temporary directory for test operations
// Returns true if created successfully, path is filled with the temp dir path
static bool clone_test_create_temp_dir(wchar_t* out_path, size_t max_len) {
    wchar_t temp_base[MAX_PATH];
    if (GetTempPathW(MAX_PATH, temp_base) == 0) return false;
    
    // Create unique subdirectory: GitSmarter_clone_<timestamp>
    DWORD tick = GetTickCount();
    swprintf_s(out_path, max_len, L"%sGitSmarter_clone_%lu", temp_base, tick);
    
    return CreateDirectoryW(out_path, nullptr) != 0;
}

// Helper: Recursively delete a directory (clone-test specific to avoid unity build conflicts)
static bool clone_test_delete_dir(const wchar_t* path) {
    wchar_t search_path[MAX_PATH];
    swprintf_s(search_path, MAX_PATH, L"%s\\*", path);
    
    WIN32_FIND_DATAW find_data;
    HANDLE find_handle = FindFirstFileW(search_path, &find_data);
    
    if (find_handle == INVALID_HANDLE_VALUE) {
        return RemoveDirectoryW(path) != 0;
    }
    
    do {
        if (wcscmp(find_data.cFileName, L".") == 0 || wcscmp(find_data.cFileName, L"..") == 0) {
            continue;
        }
        
        wchar_t full_path[MAX_PATH];
        swprintf_s(full_path, MAX_PATH, L"%s\\%s", path, find_data.cFileName);
        
        if (find_data.dwFileAttributes & FILE_ATTRIBUTE_DIRECTORY) {
            clone_test_delete_dir(full_path);
        } else {
            // Remove read-only attribute if set
            SetFileAttributesW(full_path, FILE_ATTRIBUTE_NORMAL);
            DeleteFileW(full_path);
        }
    } while (FindNextFileW(find_handle, &find_data));
    
    FindClose(find_handle);
    return RemoveDirectoryW(path) != 0;
}

