TEST(clone_remote_add_creates_remote_config) {
    wchar_t temp_dir[MAX_PATH];
    if (!clone_test_create_temp_dir(temp_dir, MAX_PATH)) {
        TEST_SKIP("Could not create temp directory");
    }
    
    // Initialize repo first
    bool result = git_repo_init(temp_dir);
    TEST_ASSERT_TRUE(result);
    
    // Open the repo
    GitRepository repo = {};
    result = git_repo_open(&repo, temp_dir);
    TEST_ASSERT_TRUE(result);
    
    // Add remote
    result = git_remote_add(&repo, "origin", "https://github.com/user/repo.git");
    TEST_ASSERT_TRUE(result);
    
    // Verify config has remote section
    wchar_t config_path[MAX_PATH];
    swprintf_s(config_path, MAX_PATH, L"%s\\.git\\config", temp_dir);
    
    char config_content[2048];
    size_t bytes_read = read_file(config_path, config_content, sizeof(config_content) - 1);
    TEST_ASSERT_TRUE(bytes_read > 0);
    config_content[bytes_read] = '\0';
    
    TEST_ASSERT_TRUE(strstr(config_content, "[remote \"origin\"]") != nullptr);
    TEST_ASSERT_TRUE(strstr(config_content, "url = https://github.com/user/repo.git") != nullptr);
    TEST_ASSERT_TRUE(strstr(config_content, "fetch = +refs/heads/*:refs/remotes/origin/*") != nullptr);
    
    git_repo_close(&repo);
    clone_test_delete_dir(temp_dir);
}

