TEST(clone_validate_url_https_valid) {
    TEST_ASSERT_TRUE(git_clone_validate_url("https://github.com/user/repo.git"));
    TEST_ASSERT_TRUE(git_clone_validate_url("https://github.com/user/repo"));
    TEST_ASSERT_TRUE(git_clone_validate_url("https://gitlab.com/user/project.git"));
    TEST_ASSERT_TRUE(git_clone_validate_url("https://bitbucket.org/team/repo.git"));
}

TEST(clone_validate_url_http_valid) {
    // HTTP URLs are valid (though less secure)
    TEST_ASSERT_TRUE(git_clone_validate_url("http://example.com/user/repo.git"));
}

TEST(clone_validate_url_invalid) {
    TEST_ASSERT_FALSE(git_clone_validate_url(nullptr));
    TEST_ASSERT_FALSE(git_clone_validate_url(""));
    TEST_ASSERT_FALSE(git_clone_validate_url("not-a-url"));
    TEST_ASSERT_FALSE(git_clone_validate_url("git@github.com:user/repo.git")); // SSH not supported in MVP
    TEST_ASSERT_FALSE(git_clone_validate_url("ftp://example.com/repo.git"));
}

TEST(clone_extract_repo_name_basic) {
    char name[256];
    
    TEST_ASSERT_TRUE(git_clone_extract_repo_name("https://github.com/user/repo.git", name, sizeof(name)));
    TEST_ASSERT_STREQ(name, "repo");
    
    TEST_ASSERT_TRUE(git_clone_extract_repo_name("https://github.com/user/repo", name, sizeof(name)));
    TEST_ASSERT_STREQ(name, "repo");
    
    TEST_ASSERT_TRUE(git_clone_extract_repo_name("https://github.com/org/my-project.git", name, sizeof(name)));
    TEST_ASSERT_STREQ(name, "my-project");
}

TEST(clone_extract_repo_name_trailing_slash) {
    char name[256];
    
    TEST_ASSERT_TRUE(git_clone_extract_repo_name("https://github.com/user/repo/", name, sizeof(name)));
    TEST_ASSERT_STREQ(name, "repo");
}

TEST(clone_extract_repo_name_invalid) {
    char name[256];
    
    TEST_ASSERT_FALSE(git_clone_extract_repo_name(nullptr, name, sizeof(name)));
    TEST_ASSERT_FALSE(git_clone_extract_repo_name("", name, sizeof(name)));
    TEST_ASSERT_FALSE(git_clone_extract_repo_name("https://github.com/", name, sizeof(name)));
}

