TEST(clone_ssh_url_rejected) {
    wchar_t temp_dir[MAX_PATH];
    if (!clone_test_create_temp_dir(temp_dir, MAX_PATH)) {
        TEST_SKIP("Could not create temp directory");
    }
    
    wchar_t dest[MAX_PATH];
    swprintf_s(dest, MAX_PATH, L"%s\\cloned_repo", temp_dir);
    
    CloneOptions options = {};
    strcpy_s(options.url, "git@github.com:user/repo.git");  // SSH URL
    wcscpy_s(options.destination, dest);
    options.checkout = true;
    
    CloneResult result = {};
    bool success = git_clone(&options, nullptr, &result);
    
    TEST_ASSERT_FALSE(success);
    TEST_ASSERT_FALSE(result.success);
    // Should mention HTTPS or invalid URL
    TEST_ASSERT_TRUE(strstr(result.error_message, "HTTPS") != nullptr ||
                     strstr(result.error_message, "Invalid") != nullptr ||
                     strstr(result.error_message, "URL") != nullptr);
    
    clone_test_delete_dir(temp_dir);
}

